import json

def compress_action_response(action_output):
    if isinstance(action_output, dict):
        # Remove verbose metadata
        cleaned = {k: v for k, v in action_output.items() 
                  if k not in ['requestId', 'timestamp', 'debug_info']}

        # Shorten nested content
        def shorten(value):
            if isinstance(value, str) and len(value) > 500:
                return value[:450] + '...'
            return value

        compressed = {k: shorten(v) for k, v in cleaned.items()}
        return compressed

    return str(action_output)[:1000]
